# ${queryName} — Catalog Service products query (fast PDP/PLP data)
query ${queryName}($skus: [String!]!) {
  products(skus: $skus) {
    sku
    name
    ... on SimpleProductView {
      price { final { amount { value currency } } }
    }
    images(roles: ["thumbnail"]) { url label }
  }
}

{
  "event": "${eventType}",
  "_note": "XDM field map for ${eventType}. Left = Commerce event field, right = XDM path. Types must match the XDM schema in your AEP sandbox.",
  "mapping": {
    "commerce.productListItems": "productListItems",
    "commerce.cart.cartID": "commerce.cart.cartID",
    "identityMap": "identityMap"
  }
}

/*
 * ${actionName} — Adobe I/O Events consumer for ${eventCode}.
 * Deliveries can repeat → idempotent on event.id.
 */
const { Core } = require('@adobe/aio-sdk');

async function main(params) {
  const logger = Core.Logger('${actionName}', { level: params.LOG_LEVEL || 'info' });
  try {
    const event = params.data || params;          // CloudEvent payload
    const eventId = params.id || event?.id;
    logger.info('event ${eventCode} received', eventId);

    // TODO idempotency: skip if eventId already processed (state/store lookup).

    // ... handle the Commerce event ...

    return { statusCode: 200, body: { ok: true, eventId } };
  } catch (error) {
    logger.error(error);
    return { statusCode: 500, body: { error: 'server error' } };
  }
}

exports.main = main;

# ${queryName} — Live Search productSearch (AI-powered, Adobe Sensei)
query ${queryName}($phrase: String!, $pageSize: Int = 12) {
  productSearch(phrase: $phrase, page_size: $pageSize) {
    total_count
    items {
      product { name sku }
      productView { ... on SimpleProductView { price { final { amount { value currency } } } } }
    }
    facets { title attribute buckets { title __typename } }
  }
}

/*
 * ${actionName} — Payment Services webhook (web action).
 * VERIFY the signature BEFORE processing. Secret from params (.env / runtime), never inline.
 */
const crypto = require('crypto');
const { Core } = require('@adobe/aio-sdk');

function verify(rawBody, signature, secret) {
  const expected = crypto.createHmac('sha256', secret).update(rawBody).digest('base64');
  return !!signature && crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected));
}

async function main(params) {
  const logger = Core.Logger('${actionName}', { level: params.LOG_LEVEL || 'info' });
  const raw = params.__ow_body || JSON.stringify(params);
  const sig = params.__ow_headers?.['x-adobe-signature'];
  if (!verify(raw, sig, params.WEBHOOK_SECRET)) {
    logger.warn('signature verification failed');
    return { statusCode: 401, body: { error: 'invalid signature' } };
  }
  // ... handle the verified payment event ...
  return { statusCode: 200, body: { ok: true } };
}

exports.main = main;
